1	/**
2	 * Content script on Google Calendar — the DOM layer of the hybrid model.
3	 *
4	 * It reads the open event surface (detail popover / expanded edit) to:
5	 *  - GATE the "Manage Visitors" button on the magic address being a guest,
6	 *  - capture the `data-eventid` (base64url "<eventId> <calendarId>"), and
7	 *  - take a best-effort SNAPSHOT (guest emails) so the panel can paint instantly
8	 *    and cover the unsaved (no-API) case.
9	 * The API layer (background) remains the authoritative source. We read only the
10	 * semantic `data-eventid`, the `[role="dialog"]` ARIA signal, and the surface's
11	 * visible text — no layout/CSS-class coupling, no injection into Google's markup.
12	 */
13	import { MAGIC_ADDRESS } from '@/lib/config';
14	import {
15	  ACTIVE_EID_KEY,
16	  ACTIVE_SNAPSHOT_KEY,
17	  NUDGE_TARGETS,
18	  PANEL_STATE,
19	} from '@/lib/messaging';
20	import type { DomEventSnapshot, VisitorEventSummary } from '@/lib/types';
21	
22	/** True while our extension context is still valid. After an extension reload or
23	 *  update, this content script is orphaned: every `chrome.*` call then throws
24	 *  "Extension context invalidated" (synchronously — `.catch()` can't see it). We
25	 *  check this before touching any chrome API so an orphan stops quietly. */
26	const extAlive = (): boolean => {
27	  try {
28	    return !!chrome.runtime?.id;
29	  } catch {
30	    return false;
31	  }
32	};
33	
34	/** sendMessage that never throws or rejects, even once the context is gone. */
35	function safeSend<T = unknown>(message: unknown): Promise<T | undefined> {
36	  if (!extAlive()) return Promise.resolve(undefined);
37	  try {
38	    return Promise.resolve(chrome.runtime.sendMessage(message)).catch(() => undefined);
39	  } catch {
40	    return Promise.resolve(undefined);
41	  }
42	}
43	
44	/** storage.session helpers that no-op once the context is gone. */
45	function safeStorageGet(key: string): Promise<Record<string, unknown>> {
46	  if (!extAlive()) return Promise.resolve({});
47	  try {
48	    return Promise.resolve(chrome.storage.session.get(key)).catch(() => ({}));
49	  } catch {
50	    return Promise.resolve({});
51	  }
52	}
53	function safeStorageSet(items: Record<string, unknown>): Promise<void> {
54	  if (!extAlive()) return Promise.resolve();
55	  try {
56	    return Promise.resolve(chrome.storage.session.set(items)).catch(() => {});
57	  } catch {
58	    return Promise.resolve();
59	  }
60	}
61	
62	export default defineContentScript({
63	  matches: ['https://calendar.google.com/*'],
64	  main() {
65	    // The id of the most recently clicked event chip — the event whose popover
66	    // is opening. Reset when the surface closes so a later unrelated dialog
67	    // can't resurrect a stale button.
68	    let clickedEid: string | null = null;
69	    let lastSnapshot: DomEventSnapshot | null = null;
70	    let panelOpen = false;
71	    let opening = false; // an OPEN_FOR_EVENT is in flight (panel not yet connected)
72	    let followedEid: string | null = null; // last event auto-pushed to the panel
73	    let pendingMagic: { eid: string; eventId: string; title: string } | null = null;
74	    let everSawEventId = false;
75	
76	    // Button UI: a native injected button when a clean anchor exists, else a
77	    // floating fallback (Idea 2). The magic-address gate is dropped — the button
78	    // shows on any open event surface; clicking it IS the intent.
79	    const button = createButtonUI(() => {
80	      if (!lastSnapshot) return;
81	      const snap = lastSnapshot;
82	      // Sanity guard: only OPEN the panel when it isn't already open (or
83	      // mid-open). If it's open, just point it at this event — clicking the
84	      // button again never fires a second sidePanel.open.
85	      if (panelOpen || opening) {
86	        followFor(snap);
87	      } else {
88	        opening = true;
89	        // Clear the latch if the panel never connects (open blocked/failed).
90	        setTimeout(() => {
91	          opening = false;
92	        }, 3000);
93	        openFor(snap); // opens the panel + sets the active event
94	      }
95	      // Note: we intentionally do NOT navigate the tab to the event here. The
96	      // panel resolves the event itself (Calendar API), so reloading the page
97	      // adds nothing but cost + surprise. "Open in Calendar" in the panel is the
98	      // explicit, user-initiated way to jump to the event.
99	    });
100	
101	    // In-page nudge banner: visitor events the user saved but hasn't acted on.
102	    // Driven by the background sync (robust), not live DOM scanning.
103	    const nudge = mountNudge();
104	    safeSend<{ ok?: boolean; data?: VisitorEventSummary[] }>({ type: 'GET_NUDGE_TARGETS' }).then(
105	      (res) => {
106	        if (res?.ok) nudge.setTargets(res.data as VisitorEventSummary[]);
107	      },
108	    );
109	
110	    // Seed the panel-open state on (re)load so auto-follow works after a
111	    // same-tab navigation (the panel persists; this content script is fresh).
112	    safeSend<{ ok?: boolean; data?: { open: boolean } }>({ type: 'GET_PANEL_STATE' }).then((res) => {
113	      if (res?.ok) {
114	        panelOpen = !!res.data?.open;
115	        nudge.setPanelOpen(panelOpen);
116	        render();
117	      }
118	    });
119	
120	    // Fast detection: sync on load, on tab focus, and right after leaving the
121	    // event editor (a likely save) — so the banner appears in seconds, not up
122	    // to a minute, and shows immediately when the user returns to the tab.
123	    let lastSync = 0;
124	    const syncNow = () => {
125	      const now = Date.now();
126	      if (now - lastSync < 4000) return; // throttle
127	      lastSync = now;
128	      safeSend({ type: 'SYNC_NOW' });
129	    };
130	    // Burst: fire several syncs after a likely save to beat Google's API
131	    // eventual-consistency lag (a fresh events.list may not show the just-saved
132	    // event for a few seconds).
133	    let lastBurst = 0;
134	    const syncBurst = () => {
135	      const now = Date.now();
136	      if (now - lastBurst < 2000) return;
137	      lastBurst = now;
138	      for (const d of [0, 3000, 8000]) {
139	        setTimeout(() => safeSend({ type: 'SYNC_NOW' }), d);
140	      }
141	    };
142	    syncNow();
143	    document.addEventListener('visibilitychange', () => {
144	      if (document.visibilityState === 'visible') syncNow();
145	    });
146	    window.addEventListener('focus', syncNow);
147	    let wasEditor = /\/eventedit/.test(location.pathname);
148	    const editorPoll = setInterval(() => {
149	      if (!extAlive()) return teardown(); // orphaned by an extension reload → stop
150	      const isEditor = /\/eventedit/.test(location.pathname);
151	      if (wasEditor && !isEditor) syncBurst(); // left the editor → likely saved
152	      wasEditor = isEditor;
153	      // Safety net: re-assert the button. The MutationObserver is debounced, so a
154	      // continuous scroll (which fires mutations faster than the debounce) can
155	      // starve it and never re-run render after Google re-renders the modal and
156	      // drops our injected button. This guarantees it comes back within ~1s.
157	      render();
158	    }, 1000);
159	
160	    // Stop all work once our context is invalidated (extension reloaded/updated),
161	    // so an orphaned script doesn't keep observing/polling — and remove our now-
162	    // dead button (its click can't reach the background) instead of leaving a
163	    // zombie that looks live but does nothing.
164	    let disposed = false;
165	    function teardown() {
166	      if (disposed) return;
167	      disposed = true;
168	      clearInterval(editorPoll);
169	      observer.disconnect();
170	      button.update(false);
171	    }
172	
173	    /** Read the open event surface, or null if none is open. `eid` may be '' for
174	     *  a brand-new, not-yet-saved event (no data-eventid / URL eid yet). */
175	    function readSurface(): { el: HTMLElement; eid: string } | null {
176	      const fromUrl = urlEid();
177	      const dialog = document.querySelector('[role="dialog"]') as HTMLElement | null;
178	      // A dialog that isn't an event surface — e.g. Google's "Send update emails
179	      // to existing guests?" save confirmation — must NEVER host our button, and
180	      // while one is open we suppress entirely so we don't inject onto it (or
181	      // behind it, over the editor). This is what kept the button appearing on
182	      // unrelated dialogs and "flashing" away when such a dialog opened/closed.
183	      if (dialog && !isEventDialog(dialog)) return null;
184	      if (fromUrl) {
185	        return { el: dialog ?? document.body, eid: fromUrl };
186	      }
187	      // Full-screen create/edit editor. An existing event always carries its eid
188	      // in the URL (handled above), so reaching here means a brand-new, unsaved
189	      // event → eid ''. Never fall back to clickedEid: it can be stale from a
190	      // previously viewed event and would point the panel at the wrong one.
191	      if (/\/eventedit/.test(location.pathname)) {
192	        return { el: dialog ?? document.body, eid: '' };
193	      }
194	      // Detail / quick-create popover.
195	      if (dialog) return { el: dialog, eid: clickedEid ?? '' };
196	      return null;
197	    }
198	
199	    function snapshotOf(el: HTMLElement, eid: string): DomEventSnapshot {
200	      const text = el.innerText || '';
201	      const lower = text.toLowerCase();
202	      const magicPresent = !!MAGIC_ADDRESS && lower.includes(MAGIC_ADDRESS);
203	      const guestEmails = extractEmails(text).filter(
204	        (e) => e.toLowerCase() !== MAGIC_ADDRESS,
205	      );
206	      // Best-effort title (cosmetic — the API sync replaces it). The editor's
207	      // title is a text input; fall back to undefined.
208	      const titleInput = el.querySelector(
209	        'input[aria-label*="title" i], input[placeholder*="title" i]',
210	      ) as HTMLInputElement | null;
211	      const title = titleInput?.value?.trim() || undefined;
212	      return { eid, magicPresent, guestEmails, title };
213	    }
214	
215	    function render() {
216	      if (!extAlive()) return teardown(); // orphaned by an extension reload → stop
217	      const surface = readSurface();
218	      lastSnapshot = surface ? snapshotOf(surface.el, surface.eid) : null;
219	
220	      // Instant nudge: while viewing a visitor event WITH a real eid, remember
221	      // it; when the user then leaves that surface (closed popover / saved &
222	      // left editor), show the nudge for it IMMEDIATELY — no API round-trip.
223	      if (lastSnapshot?.magicPresent && lastSnapshot.eid) {
224	        pendingMagic = {
225	          eid: lastSnapshot.eid,
226	          eventId: decodeEventId(lastSnapshot.eid),
227	          title: lastSnapshot.title ?? '',
228	        };
229	      } else if (!surface && pendingMagic) {
230	        nudge.addOptimistic({
231	          eid: pendingMagic.eid,
232	          eventId: pendingMagic.eventId,
233	          iCalUid: '',
234	          title: pendingMagic.title,
235	          start: undefined,
236	        });
237	        syncBurst(); // confirm/refresh from the API right after
238	        pendingMagic = null;
239	      }
240	
241	      // Show the button on any open event surface — including while the panel
242	      // is open, so it stays available as an explicit "show this event" control.
243	      // Suppress the floating fallback while the panel is open: it's redundant
244	      // (auto-follow handles the viewed event) and would flash at the corner
245	      // while a navigated edit page is still loading.
246	      button.update(!!surface, !panelOpen);
247	      if (panelOpen) maybeFollow();
248	    }
249	
250	    /** Push the open *saved* event to the panel so it follows what you're viewing.
251	     *  Saved only (non-empty eid); deduped; the panel guards against switching
252	     *  mid-action. */
253	    function maybeFollow() {
254	      const snap = lastSnapshot;
255	      if (!snap || !snap.eid) return; // new/unsaved events don't auto-switch
256	      if (snap.eid === followedEid) return;
257	      followedEid = snap.eid;
258	      safeSend({ type: 'FOLLOW_EVENT', eid: snap.eid, snapshot: snap });
259	    }
260	
261	    document.addEventListener(
262	      'click',
263	      (e) => {
264	        const chip = (e.target as Element | null)?.closest?.('[data-eventid]');
265	        const id = chip?.getAttribute('data-eventid');
266	        if (id) {
267	          everSawEventId = true;
268	          clickedEid = id;
269	        }
270	        setTimeout(render, 60); // let the popover render
271	      },
272	      true,
273	    );
274	
275	    document.addEventListener(
276	      'keydown',
277	      (e) => {
278	        if (e.key === 'Escape') {
279	          clickedEid = null;
280	          setTimeout(render, 60);
281	        }
282	      },
283	      true,
284	    );
285	
286	    // Detect surface open/close + edits (e.g. adding the magic address live).
287	    let timer: number | undefined;
288	    const observer = new MutationObserver(() => {
289	      clearTimeout(timer);
290	      timer = setTimeout(() => {
291	        if (!document.querySelector('[role="dialog"]') && !urlEid()) {
292	          clickedEid = null;
293	        }
294	        render();
295	      }, 150) as unknown as number;
296	    });
297	    observer.observe(document.body, { childList: true, subtree: true });
298	
299	    window.addEventListener('popstate', render);
300	
301	    // Hide the in-page button while the side panel is open.
302	    chrome.runtime.onMessage.addListener(
303	      (msg: {
304	        type?: string;
305	        open?: boolean;
306	        targets?: VisitorEventSummary[];
307	        cancelled?: string[];
308	      }) => {
309	        if (msg?.type === PANEL_STATE) {
310	          panelOpen = !!msg.open;
311	          if (panelOpen) opening = false; // connected → clear the open latch
312	          if (!panelOpen) followedEid = null; // re-follow next time it opens
313	          nudge.setPanelOpen(panelOpen); // banner hides while the panel is open
314	          render();
315	        } else if (msg?.type === NUDGE_TARGETS) {
316	          nudge.setTargets(msg.targets ?? [], msg.cancelled ?? []);
317	        }
318	      },
319	    );
320	
321	    setTimeout(() => {
322	      if (!everSawEventId && !document.querySelector('[data-eventid]')) {
323	        console.warn(
324	          '[auxilio] no [data-eventid] found — click detection may be unavailable; use the panel’s event list.',
325	        );
326	      }
327	    }, 90_000);
328	
329	    render();
330	    console.log('[auxilio] content script ready on Google Calendar');
331	  },
332	});
333	
334	function openFor(snapshot: DomEventSnapshot) {
335	  return safeSend({ type: 'OPEN_FOR_EVENT', eid: snapshot.eid, snapshot });
336	}
337	
338	/** Point the already-open panel at an event without re-opening it. */
339	function followFor(snapshot: DomEventSnapshot) {
340	  return safeSend({ type: 'FOLLOW_EVENT', eid: snapshot.eid, snapshot });
341	}
342	
343	/** Event id from the expanded-edit URL path, if present. */
344	function urlEid(): string | null {
345	  const path = location.pathname.match(/\/eventedit\/([^/?#]+)/);
346	  if (path && path[1] !== 'eventedit') return safeDecode(path[1]);
347	  const q = new URLSearchParams(location.search).get('eid');
348	  return q ? safeDecode(q) : null;
349	}
350	
351	/** Pull unique email-looking strings from text (best-effort guest scrape). */
352	function extractEmails(text: string): string[] {
353	  const matches = text.match(/[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}/gi) ?? [];
354	  return [...new Set(matches.map((m) => m.toLowerCase()))];
355	}
356	
357	/** eid (base64url of "<eventId> <calendarId>") → eventId, for nudge dedup. */
358	function decodeEventId(eid: string): string {
359	  try {
360	    let b64 = eid.replace(/-/g, '+').replace(/_/g, '/');
361	    b64 += '='.repeat((4 - (b64.length % 4)) % 4);
362	    return atob(b64).split(' ')[0] || '';
363	  } catch {
364	    return '';
365	  }
366	}
367	
368	function safeDecode(s: string): string {
369	  try {
370	    return decodeURIComponent(s);
371	  } catch {
372	    return s;
373	  }
374	}
375	
376	const USERS_SVG = `
377	<svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24"
378	  fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round">
379	  <path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/>
380	  <path d="M22 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg>`;
381	
382	const LABEL = 'Manage Visitors';
383	const INJECT_ID = 'auxilio-manage-visitors';
384	
385	/**
386	 * Button UI manager: injects a native-styled "Manage Visitors" button as a real,
387	 * full-width row in the surface — below the Availability/Visibility section on the
388	 * edit page, at the bottom of the outermost content list in the detail popover (so
389	 * it scrolls with the rest of the UI, never an overlay) — and falls back to a
390	 * floating button only when no anchor is found. `update(show)` decides per render.
391	 */
392	function createButtonUI(onClick: () => void) {
393	  const fab = mountFloating(onClick);
394	  let injected: HTMLElement | null = null;
395	  let retryTimer: ReturnType<typeof setTimeout> | undefined;
396	
397	  // A clean injection anchor: where to drop the button + how far to indent it so
398	  // it lines up with the section's content column (past Google's icon gutter).
399	  // `inline` = sit next to a native button instead of as its own row.
400	  type Anchor = { insert: (el: HTMLElement) => void; inset: number; inline?: boolean };
401	
402	  /** Text/ARIA-based only — never CSS classes — so we stay decoupled from
403	   *  Google's obfuscated markup. Places the button where it reads as part of the
404	   *  form: between Description and the next section on the edit page, and as the
405	   *  last row of the detail popover's content list. Floating only as last resort. */
406	  function findAnchor(): Anchor | null {
407	    // Full-screen edit page → our own row just BELOW the Availability/Visibility
408	    // info section (falling back to above Description).
409	    if (/\/eventedit/.test(location.pathname)) {
410	      const avail = findAvailabilityInfo();
411	      const afterAvail = avail ? rowsListFor(avail) : null;
412	      if (afterAvail) {
413	        const { list, row } = afterAvail;
414	        return { insert: (el) => list.insertBefore(el, row.nextSibling), inset: rowInset(row, list) };
415	      }
416	      const desc = findEditDescription();
417	      const aboveDesc = desc ? rowsListFor(desc) : null;
418	      if (aboveDesc) {
419	        const { list, row } = aboveDesc;
420	        return { insert: (el) => list.insertBefore(el, row), inset: rowInset(row, list) };
421	      }
422	      // Fallback within the edit page: inline, right before the native "Save".
423	      const save = findButtonByText('save');
424	      const parent = save?.parentElement;
425	      if (save && parent) return { insert: (el) => parent.insertBefore(el, save), inset: 0, inline: true };
426	      return null;
427	    }
428	    // Detail popover / modal → BOTTOM of the OUTERMOST content list (after every
429	    // section, including the guest list). Robust whether or not guests exist.
430	    const dialog = document.querySelector<HTMLElement>('[role="dialog"]');
431	    if (dialog) {
432	      const list = findContentList(dialog);
433	      if (list) {
434	        const ref = firstIconLedRow(list);
435	        return { insert: (el) => list.appendChild(el), inset: ref ? rowInset(ref, list) : 0 };
436	      }
437	      // Fallback → bottom of the scrolling content.
438	      const scope = scrollContainer(dialog) ?? dialog;
439	      const l = mainVerticalList(scope) ?? scope;
440	      return { insert: (el) => l.appendChild(el), inset: 0 };
441	    }
442	    return null;
443	  }
444	
445	  function ensureInjected(): boolean {
446	    if (injected && injected.isConnected) return true; // still placed — skip the scan
447	    const anchor = findAnchor();
448	    if (!anchor) return false;
449	    removeInjected();
450	    ensureInjectedStyles();
451	    injected = anchor.inline
452	      ? buildInlineButton(onClick)
453	      : buildInjectedRow(onClick, anchor.inset);
454	    anchor.insert(injected);
455	    return true;
456	  }
457	
458	  function removeInjected() {
459	    injected?.remove();
460	    injected = null;
461	  }
462	
463	  return {
464	    // `allowFab` gates the floating fallback. It's only there to surface the
465	    // panel when we can't inject a native button; with the panel already open
466	    // it's redundant (auto-follow handles the viewed event), and it would flash
467	    // at the corner while a navigated page is still loading. So callers pass
468	    // false when the panel is open.
469	    update(show: boolean, allowFab = true) {
470	      clearTimeout(retryTimer);
471	      if (!show) {
472	        removeInjected();
473	        fab.setVisible(false);
474	        return;
475	      }
476	      // Try to inject now; if the anchor isn't in the DOM / laid out yet (Google
477	      // is still rendering the surface), keep retrying for a few seconds. The
478	      // MutationObserver covers DOM changes, but layout can settle — giving
479	      // elements their width — without a childList mutation, so width-based
480	      // anchor checks can miss that window. This retry guarantees we don't.
481	      let attempts = 0;
482	      const attempt = () => {
483	        const placed = ensureInjected();
484	        // Show the floating fallback only after a short grace period, so on a
485	        // normally-rendering surface the native button just appears — no flash
486	        // of the FAB getting replaced a moment later.
487	        fab.setVisible(allowFab && !placed && attempts >= 3);
488	        if (placed || attempts++ >= 30) return;
489	        retryTimer = setTimeout(attempt, 150);
490	      };
491	      attempt();
492	    },
493	  };
494	}
495	
496	/**
497	 * Is this open `[role="dialog"]` an actual event surface (detail popover / quick
498	 * edit), rather than one of Google's transient confirmation dialogs — e.g.
499	 * "Send update emails to existing Google Calendar guests?" or "Delete this
500	 * event?" — which we must not decorate? Positive, stable signals only: an event
501	 * chip id, the magic address in its text, or several icon-led section rows
502	 * (time / guests / location). A confirmation dialog is just a question plus a
503	 * row of action buttons, so it matches none of these.
504	 */
505	function isEventDialog(dialog: HTMLElement): boolean {
506	  if (dialog.querySelector('[data-eventid]')) return true;
507	  const text = (dialog.innerText || '').toLowerCase();
508	  if (MAGIC_ADDRESS && text.includes(MAGIC_ADDRESS)) return true;
509	  return !!findContentList(dialog);
510	}
511	
512	/** Find a clickable element whose visible text matches (case-insensitive). */
513	function findButtonByText(text: string): HTMLElement | null {
514	  const wanted = text.toLowerCase();
515	  const els = document.querySelectorAll<HTMLElement>('button,[role="button"]');
516	  for (const el of els) {
517	    if ((el.textContent ?? '').trim().toLowerCase() === wanted) return el;
518	  }
519	  return null;
520	}
521	
522	const isVisible = (el: HTMLElement) => el.offsetParent !== null || el.getClientRects().length > 0;
523	
524	/** The Description editor on the event edit page. ARIA/placeholder text only —
525	 *  never CSS classes (Google's are obfuscated and churn). */
526	function findEditDescription(): HTMLElement | null {
527	  const els = document.querySelectorAll<HTMLElement>(
528	    '[aria-label*="description" i], [placeholder*="description" i]',
529	  );
530	  for (const el of els) if (isVisible(el)) return el;
531	  return null;
532	}
533	
534	/** The Availability/Visibility info block on the edit page. Prefers Google's
535	 *  stable `jsname` hook, falling back to the info text. */
536	function findAvailabilityInfo(): HTMLElement | null {
537	  const byJsname = document.querySelector<HTMLElement>('[jsname="g7cnnb"]');
538	  if (byJsname && isVisible(byJsname)) return byJsname;
539	  for (const el of document.querySelectorAll<HTMLElement>('span,div')) {
540	    const t = (el.textContent ?? '').trim().toLowerCase();
541	    if (t.startsWith('availability might be shown') && isVisible(el)) return el;
542	  }
543	  return null;
544	}
545	
546	/** The OUTERMOST rows list inside `root`: the shallowest container whose own
547	 *  children include several icon-led section rows. Breadth-first so a nested
548	 *  guest list never wins over the main content list. */
549	function findContentList(root: HTMLElement): HTMLElement | null {
550	  const queue: HTMLElement[] = [];
551	  for (const c of root.children) if (c instanceof HTMLElement) queue.push(c);
552	  while (queue.length) {
553	    const el = queue.shift()!;
554	    if (!isVisible(el)) continue;
555	    if (iconLedRowCount(el) >= 2) return el;
556	    for (const c of el.children) if (c instanceof HTMLElement) queue.push(c);
557	  }
558	  return null;
559	}
560	
561	/** The first wide icon-led row in a list — a reference for measuring the text
562	 *  column inset. */
563	function firstIconLedRow(list: HTMLElement): HTMLElement | null {
564	  const lw = list.getBoundingClientRect().width;
565	  for (const c of list.children) {
566	    if (!(c instanceof HTMLElement) || !isVisible(c) || !looksLikeRow(c)) continue;
567	    if (lw > 0 && c.getBoundingClientRect().width < lw * 0.5) continue;
568	    return c;
569	  }
570	  return null;
571	}
572	
573	/** Does this element stack its visible children vertically (a column of rows),
574	 *  rather than laying them out side by side? Geometry, not CSS classes. */
575	function stacksVertically(el: HTMLElement): boolean {
576	  const kids = [...el.children].filter((c): c is HTMLElement => c instanceof HTMLElement && isVisible(c));
577	  if (kids.length < 2) return false;
578	  for (let i = 1; i < kids.length; i++) {
579	    const a = kids[i - 1].getBoundingClientRect();
580	    const b = kids[i].getBoundingClientRect();
581	    if (b.top >= a.bottom - 2) return true; // the next child starts below the previous
582	  }
583	  return false;
584	}
585	
586	/** A native Calendar content row = a block whose first child is a decorative
587	 *  (aria-hidden) leading icon, followed by content. This is the one stable,
588	 *  class-free signal Google keeps across both the popover and the edit page. */
589	function looksLikeRow(el: HTMLElement): boolean {
590	  const first = el.firstElementChild;
591	  return (
592	    !!first &&
593	    el.childElementCount >= 2 &&
594	    (first.getAttribute('aria-hidden') === 'true' ||
595	      !!first.querySelector('svg, img, i.google-material-icons'))
596	  );
597	}
598	
599	/** How many of a container's visible children are icon-led *section* rows.
600	 *  Rows must span most of the container's width, which excludes narrow icon
601	 *  clusters like a description formatting toolbar. */
602	function iconLedRowCount(container: HTMLElement): number {
603	  const cw = container.getBoundingClientRect().width;
604	  let n = 0;
605	  for (const c of container.children) {
606	    if (!(c instanceof HTMLElement) || !isVisible(c) || !looksLikeRow(c)) continue;
607	    if (cw > 0 && c.getBoundingClientRect().width < cw * 0.5) continue; // skip toolbars/chips
608	    n++;
609	  }
610	  return n;
611	}
612	
613	/** From a field/label, climb to the rows list that holds it: the first ancestor
614	 *  whose parent contains several icon-led rows. Returns that list plus the row
615	 *  (a direct child of the list) that contains `el` — so we can insert relative
616	 *  to it. Null if no rows list is recognised. */
617	function rowsListFor(el: HTMLElement): { list: HTMLElement; row: HTMLElement } | null {
618	  let node: HTMLElement = el;
619	  while (node.parentElement && node.parentElement !== document.body) {
620	    const parent = node.parentElement;
621	    if (iconLedRowCount(parent) >= 2) return { list: parent, row: node };
622	    node = parent;
623	  }
624	  return null;
625	}
626	
627	/** The biggest vertically-stacking container inside `root` — the content column
628	 *  whose last child is the visual bottom of the surface. */
629	function mainVerticalList(root: HTMLElement): HTMLElement | null {
630	  let best: HTMLElement | null = null;
631	  let bestArea = 0;
632	  for (const el of root.querySelectorAll<HTMLElement>('*')) {
633	    if (!isVisible(el) || !stacksVertically(el)) continue;
634	    const r = el.getBoundingClientRect();
635	    const area = r.width * r.height;
636	    if (area > bestArea) {
637	      bestArea = area;
638	      best = el;
639	    }
640	  }
641	  return best;
642	}
643	
644	/** Left indent (px) that lines our button up with a native row's *text* column,
645	 *  past Google's leading icon gutter. Measured from where the row's first text
646	 *  actually paints, relative to the list we insert into. */
647	function rowInset(row: HTMLElement, list: HTMLElement): number {
648	  const gap = firstTextLeft(row) - list.getBoundingClientRect().left;
649	  return Number.isFinite(gap) && gap > 0 && gap < 240 ? Math.round(gap) : 0;
650	}
651	
652	/** Left edge of the first painted text inside `el` (skips the decorative icon
653	 *  gutter), or the element's own left if it has none. */
654	function firstTextLeft(el: HTMLElement): number {
655	  const walker = document.createTreeWalker(el, NodeFilter.SHOW_TEXT);
656	  let node: Node | null;
657	  while ((node = walker.nextNode())) {
658	    if (!node.textContent || !node.textContent.trim()) continue;
659	    const range = document.createRange();
660	    range.selectNodeContents(node);
661	    const rect = range.getBoundingClientRect();
662	    if (rect.width > 0) return rect.left;
663	  }
664	  return el.getBoundingClientRect().left;
665	}
666	
667	/** The scrolling content region inside a surface (overflow-y auto/scroll),
668	 *  largest first — so our row lives with the content and scrolls, not in a
669	 *  pinned header/footer. Null when nothing scrolls. */
670	function scrollContainer(root: HTMLElement): HTMLElement | null {
671	  let best: HTMLElement | null = null;
672	  let bestArea = 0;
673	  for (const el of root.querySelectorAll<HTMLElement>('*')) {
674	    if (!isVisible(el)) continue;
675	    const oy = getComputedStyle(el).overflowY;
676	    if (oy !== 'auto' && oy !== 'scroll') continue;
677	    const r = el.getBoundingClientRect();
678	    const area = r.width * r.height;
679	    if (area > bestArea) {
680	      bestArea = area;
681	      best = el;
682	    }
683	  }
684	  return best;
685	}
686	
687	/** Stop our interactions dismissing Google's modal / triggering its buttons. */
688	function shieldInteractions(el: HTMLElement) {
689	  for (const type of ['pointerdown', 'mousedown', 'touchstart'] as const) {
690	    el.addEventListener(
691	      type,
692	      (e) => {
693	        e.stopPropagation();
694	        e.preventDefault(); // don't move focus out of the Calendar dialog
695	      },
696	      true,
697	    );
698	  }
699	  el.addEventListener('click', (e) => e.stopPropagation(), true);
700	}
701	
702	const STYLE_ID = 'auxilio-manage-visitors-style';
703	
704	/** One-time stylesheet for the injected (light-DOM) button. Styled to match a
705	 *  native Material outlined Calendar button — same shape, size, typography and
706	 *  hover state-layer — so it reads as part of Google's UI, just brand-tinted. */
707	function ensureInjectedStyles() {
708	  if (document.getElementById(STYLE_ID)) return;
709	  const s = document.createElement('style');
710	  s.id = STYLE_ID;
711	  s.textContent = `
712	    .auxilio-mv-row{box-sizing:border-box;display:flex;align-items:center;width:100%;padding:8px 0;}
713	    .auxilio-mv-btn{
714	      box-sizing:border-box;display:inline-flex;align-items:center;gap:8px;
715	      font-family:'Google Sans','Roboto',Arial,sans-serif;font-size:14px;font-weight:500;
716	      line-height:20px;letter-spacing:.25px;color:#92288e;background:transparent;
717	      border:1px solid #747775;border-radius:999px;padding:8px 18px 8px 14px;
718	      min-height:40px;cursor:pointer;white-space:nowrap;
719	      transition:background-color 120ms ease,border-color 120ms ease;
720	    }
721	    .auxilio-mv-btn:hover{background:rgba(146,40,142,.08);}
722	    .auxilio-mv-btn:active{background:rgba(146,40,142,.12);}
723	    .auxilio-mv-btn:focus-visible{outline:2px solid #92288e;outline-offset:2px;}
724	    .auxilio-mv-btn[disabled]{opacity:.6;cursor:default;}
725	    .auxilio-mv-btn svg{width:18px;height:18px;flex:0 0 auto;}
726	  `;
727	  document.documentElement.appendChild(s);
728	}
729	
730	/** The native-styled button itself (light DOM, classes from ensureInjectedStyles). */
731	function makeNativeButton(onClick: () => void): HTMLButtonElement {
732	  const btn = document.createElement('button');
733	  btn.type = 'button';
734	  btn.className = 'auxilio-mv-btn';
735	  btn.innerHTML = `${USERS_SVG}<span>${LABEL}</span>`;
736	  shieldInteractions(btn);
737	  wireActivate(btn, onClick);
738	  return btn;
739	}
740	
741	/** A full-width row carrying the button, indented to align with the section
742	 *  content column. Flows like a native section, so it can't overlap siblings. */
743	function buildInjectedRow(onClick: () => void, inset: number): HTMLElement {
744	  const row = document.createElement('div');
745	  row.id = INJECT_ID;
746	  row.className = 'auxilio-mv-row';
747	  if (inset) row.style.paddingLeft = `${inset}px`;
748	  row.appendChild(makeNativeButton(onClick));
749	  // Guard only the row's empty padding — clicks there must not dismiss Google's
750	  // surface; the button manages its own interactions (shieldInteractions).
751	  shieldPadding(row);
752	  return row;
753	}
754	
755	/** Inline button for the before-Save fallback (sits next to a native action). */
756	function buildInlineButton(onClick: () => void): HTMLButtonElement {
757	  const btn = makeNativeButton(onClick);
758	  btn.id = INJECT_ID;
759	  btn.style.marginRight = '8px';
760	  return btn;
761	}
762	
763	/** Stop interactions on the row's own padding (but not the button) from reaching
764	 *  Google — so an accidental tap beside the button can't close the dialog. */
765	function shieldPadding(row: HTMLElement) {
766	  const guard = (e: Event) => {
767	    if (e.target === row) {
768	      e.preventDefault();
769	      e.stopPropagation();
770	    }
771	  };
772	  for (const type of ['pointerdown', 'mousedown', 'touchstart', 'click'] as const) {
773	    row.addEventListener(type, guard, true);
774	  }
775	}
776	
777	/** Floating fallback button (shadow-DOM, fully isolated). */
778	function mountFloating(onClick: () => void) {
779	  const host = document.createElement('div');
780	  // pointer-events:none so the host box never eats clicks on what's beneath it when
781	  // the FAB is hidden — the inner button is display:inline-flex even when invisible, so
782	  // the host keeps a bounding box at bottom-right that would otherwise sit over (and
783	  // swallow clicks for) Google's own bottom drawer buttons (e.g. the event-edit add-on
784	  // drawer's "View"). The shown button re-enables hits via `.fab.show{pointer-events:auto}`.
785	  host.style.cssText = 'position:fixed;right:24px;bottom:24px;z-index:2147483646;pointer-events:none;';
786	  document.documentElement.appendChild(host);
787	  const root = host.attachShadow({ mode: 'open' });
788	  root.innerHTML = `
789	    <style>
790	      :host { all: initial; }
791	      .fab {
792	        display:inline-flex;align-items:center;gap:8px;
793	        font-family:'Google Sans','Roboto',system-ui,sans-serif;font-size:14px;font-weight:600;
794	        color:#fff;background:#92288e;border:none;border-radius:999px;padding:12px 18px;
795	        box-shadow:0 2px 6px rgba(0,0,0,.18);cursor:pointer;
796	        transform:translateY(8px);opacity:0;pointer-events:none;
797	        transition:opacity 200ms cubic-bezier(.2,0,0,1),transform 200ms cubic-bezier(.2,0,0,1),box-shadow 120ms ease;
798	      }
799	      .fab.show{opacity:1;transform:none;pointer-events:auto;}
800	      .fab:hover{box-shadow:0 4px 12px rgba(0,0,0,.24);}
801	      .fab:active{transform:scale(.98);}
802	      .fab[disabled]{opacity:.6;pointer-events:none;}
803	      @media (prefers-reduced-motion: reduce){.fab{transition:none;transform:none;}}
804	    </style>
805	    <button class="fab" type="button">${USERS_SVG}<span class="label">${LABEL}</span></button>`;
806	  const btn = root.querySelector('button') as HTMLButtonElement;
807	  shieldInteractions(host);
808	  wireActivate(btn, onClick);
809	  return {
810	    setVisible(v: boolean) {
811	      btn.classList.toggle('show', v);
812	    },
813	  };
814	}
815	
816	/** Shared activate handler (pointerup + click, double-fire-guarded). */
817	function wireActivate(btn: HTMLButtonElement, onClick: () => void) {
818	  const label = btn.querySelector('span:last-of-type') as HTMLSpanElement | null;
819	  let firing = false;
820	  const activate = async () => {
821	    if (firing) return;
822	    firing = true;
823	    btn.disabled = true;
824	    const prev = label?.textContent;
825	    if (label) label.textContent = 'Opening…';
826	    try {
827	      await onClick();
828	    } finally {
829	      btn.disabled = false;
830	      if (label && prev) label.textContent = prev;
831	      firing = false;
832	    }
833	  };
834	  btn.addEventListener('pointerup', activate);
835	  btn.addEventListener('click', activate);
836	}
837	
838	const NUDGE_DISMISS_KEY = 'auxilio.dismissedNudges';
839	const BELL_SVG = `
840	<svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24"
841	  fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round">
842	  <path d="M10.268 21a2 2 0 0 0 3.464 0"/><path d="M3.262 15.326A1 1 0 0 0 4 17h16a1 1 0 0 0 .74-1.673C19.41 13.956 18 12.499 18 8A6 6 0 0 0 6 8c0 4.499-1.411 5.956-2.738 7.326"/></svg>`;
843	const NUDGE_X_SVG = `
844	<svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24"
845	  fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round">
846	  <path d="M18 6 6 18"/><path d="m6 6 12 12"/></svg>`;
847	
848	/**
849	 * In-page nudge banner (sync-driven). Shows the soonest visitor event the user
850	 * saved but hasn't acted on. "Manage" opens the panel AND navigates this tab to
851	 * the event — one click opens both. Dismissals persist in storage.session.
852	 */
853	function mountNudge() {
854	  const host = document.createElement('div');
855	  // pointer-events:none so the (always-present) host box doesn't swallow clicks on the
856	  // Calendar UI beneath it while the banner is hidden — the banner is display:flex even
857	  // when invisible, so the host keeps a box at top-center. `.banner.show{pointer-events:auto}`
858	  // restores hits when it's actually shown.
859	  host.style.cssText =
860	    'position:fixed;top:72px;left:50%;transform:translateX(-50%);z-index:2147483647;pointer-events:none;';
861	  document.documentElement.appendChild(host);
862	  const root = host.attachShadow({ mode: 'open' });
863	  root.innerHTML = `
864	    <style>
865	      :host { all: initial; }
866	      .banner {
867	        display:flex;align-items:center;gap:12px;max-width:520px;
868	        font-family:'Google Sans','Roboto',system-ui,sans-serif;color:#310031;
869	        background:#f8d9f5;border:1px solid #92288e33;border-radius:14px;
870	        padding:10px 12px 10px 16px;box-shadow:0 4px 12px rgba(0,0,0,.18);
871	        transform:translateY(-12px);opacity:0;pointer-events:none;
872	        transition:opacity 200ms cubic-bezier(.2,0,0,1),transform 200ms cubic-bezier(.2,0,0,1);
873	      }
874	      .banner.show{opacity:1;transform:none;pointer-events:auto;}
875	      .icon{display:inline-flex;color:#92288e;flex:0 0 auto;}
876	      .text{font-size:13.5px;line-height:18px;}
877	      .text b{font-weight:600;}
878	      .actions{display:flex;align-items:center;gap:4px;flex:0 0 auto;}
879	      .manage{font:inherit;font-size:13px;font-weight:600;color:#fff;background:#92288e;
880	        border:none;border-radius:999px;padding:8px 14px;cursor:pointer;}
881	      .manage:hover{box-shadow:0 2px 6px rgba(0,0,0,.2);}
882	      .dismiss{display:inline-flex;align-items:center;justify-content:center;width:30px;height:30px;
883	        border:none;border-radius:50%;background:transparent;color:#5f5560;cursor:pointer;}
884	      .dismiss:hover{background:#0000000f;}
885	      @media (prefers-reduced-motion: reduce){.banner{transition:none;transform:none;}}
886	    </style>
887	    <div class="banner">
888	      <span class="icon">${BELL_SVG}</span>
889	      <span class="text"></span>
890	      <span class="actions">
891	        <button class="manage" type="button">Manage</button>
892	        <button class="dismiss" type="button" aria-label="Dismiss">${NUDGE_X_SVG}</button>
893	      </span>
894	    </div>`;
895	  const wrap = root.querySelector('.banner') as HTMLDivElement;
896	  const text = root.querySelector('.text') as HTMLSpanElement;
897	  const manageBtn = root.querySelector('.manage') as HTMLButtonElement;
898	  const dismissBtn = root.querySelector('.dismiss') as HTMLButtonElement;
899	  shieldInteractions(host);
900	
901	  let targets: VisitorEventSummary[] = [];
902	  // Optimistic, DOM-derived targets shown INSTANTLY (no API wait) for an event
903	  // the user just interacted with; the API sync reconciles them by eventId.
904	  const optimistic = new Map<string, VisitorEventSummary>();
905	  // Each optimistic guess is provisional: if the sync never confirms it as a
906	  // real visitor event (e.g. the event was deleted, already handled, or the
907	  // magic address removed), it self-expires rather than lingering forever.
908	  const optimisticTimers = new Map<string, ReturnType<typeof setTimeout>>();
909	  const OPTIMISTIC_TTL = 12_000;
910	  const dropOptimistic = (eventId: string) => {
911	    const timer = optimisticTimers.get(eventId);
912	    if (timer) clearTimeout(timer);
913	    optimisticTimers.delete(eventId);
914	    optimistic.delete(eventId);
915	  };
916	  let panelOpen = false;
917	  let dismissed = new Set<string>();
918	  let current: VisitorEventSummary | null = null;
919	
920	  safeStorageGet(NUDGE_DISMISS_KEY).then((r) => {
921	    dismissed = new Set((r[NUDGE_DISMISS_KEY] as string[]) ?? []);
922	    render();
923	  });
924	
925	  /** Merged, deduped, soonest-first (synced target wins over optimistic). */
926	  function merged(): VisitorEventSummary[] {
927	    const byId = new Map<string, VisitorEventSummary>();
928	    for (const o of optimistic.values()) byId.set(o.eventId, o);
929	    for (const t of targets) byId.set(t.eventId, t); // synced data wins
930	    return [...byId.values()].sort((a, b) =>
931	      (a.start ?? '~').localeCompare(b.start ?? '~'),
932	    );
933	  }
934	
935	  function visible(): VisitorEventSummary | null {
936	    return merged().find((t) => !dismissed.has(t.eventId)) ?? null;
937	  }
938	
939	  function render() {
940	    const t = panelOpen ? null : visible();
941	    current = t;
942	    if (!t) {
943	      wrap.classList.remove('show');
944	      return;
945	    }
946	    const more = merged().filter((x) => !dismissed.has(x.eventId)).length - 1;
947	    text.innerHTML =
948	      `<b>Visitor event needs passes.</b> ${escapeText(t.title || '')}` +
949	      (more > 0 ? ` <span style="opacity:.7">+${more} more</span>` : '');
950	    wrap.classList.add('show');
951	  }
952	
953	  // Use pointerup (not click): the host's capture-phase shield — which stops our
954	  // interactions from dismissing Google's modal — would otherwise swallow click.
955	  manageBtn.addEventListener('pointerup', () => {
956	    if (!current) return;
957	    const target = current;
958	    manageBtn.disabled = true;
959	    manageBtn.textContent = 'Opening…';
960	    // Engaging with the event clears its nudge for the session, so it doesn't
961	    // reappear when the panel closes (or when the optimistic re-add fires).
962	    dismissed.add(target.eventId);
963	    safeStorageSet({ [NUDGE_DISMISS_KEY]: [...dismissed] });
964	    render(); // hide the banner now
965	    // Set the active event FIRST (storage.session, now content-accessible) so the
966	    // panel has it the moment it mounts — no dependence on message ordering.
967	    safeStorageSet({ [ACTIVE_EID_KEY]: target.eid, [ACTIVE_SNAPSHOT_KEY]: null });
968	    // Open the panel within this gesture. We don't navigate the tab — the panel
969	    // resolves the event on its own; "Open in Calendar" there is the explicit way
970	    // to jump to it.
971	    safeSend({ type: 'OPEN_FOR_EVENT', eid: target.eid }).finally(() => {
972	      manageBtn.disabled = false;
973	      manageBtn.textContent = 'Manage';
974	    });
975	  });
976	
977	  dismissBtn.addEventListener('pointerup', () => {
978	    if (!current) return;
979	    dismissed.add(current.eventId);
980	    safeStorageSet({ [NUDGE_DISMISS_KEY]: [...dismissed] });
981	    render();
982	  });
983	
984	  return {
985	    setTargets(next: VisitorEventSummary[], cancelled: string[] = []) {
986	      targets = next ?? [];
987	      // The sync authoritatively resolved these away (deleted/cancelled/no
988	      // longer a visitor event) → purge any optimistic guess so a deleted
989	      // event can't keep nudging (or reopen the panel for a ghost event).
990	      for (const id of cancelled) dropOptimistic(id);
991	      // Drop optimistic entries the real sync now covers.
992	      for (const t of targets) dropOptimistic(t.eventId);
993	      render();
994	    },
995	    addOptimistic(s: VisitorEventSummary) {
996	      optimistic.set(s.eventId, s);
997	      const existing = optimisticTimers.get(s.eventId);
998	      if (existing) clearTimeout(existing);
999	      optimisticTimers.set(
1000	        s.eventId,
1001	        setTimeout(() => {
1002	          optimistic.delete(s.eventId);
1003	          optimisticTimers.delete(s.eventId);
1004	          render();
1005	        }, OPTIMISTIC_TTL),
1006	      );
1007	      render();
1008	    },
1009	    setPanelOpen(open: boolean) {
1010	      panelOpen = open;
1011	      render();
1012	    },
1013	  };
1014	}
1015	
1016	function escapeText(s: string): string {
1017	  const d = document.createElement('div');
1018	  d.textContent = s;
1019	  return d.innerHTML;
1020	}
