if (pathname.startsWith('/api/visitor/calendar/addon/')) {
  const identity = await verifyAddonIdToken(req.headers.authorization);
  if (!identity) {
    json(res, 401, { error: 'invalid or missing add-on identity token' });
    return true;
  }
  if (!isInternalHostEmail(identity.email)) {
    json(res, 403, { error: 'host domain not allowed' });
    return true;
  }

  // POST /addon/draft — load (or lazily build + pre-fill) the Visit Draft.
  if (pathname === '/api/visitor/calendar/addon/draft' && method === 'POST') {
    const body = await readBodyJson(req);
    const iCalUid = String(body.iCalUid ?? '').trim();
    if (!iCalUid) { json(res, 422, { error: 'iCalUid required' }); return true; }
    const attendees = Array.isArray(body.attendees)
      ? (body.attendees as { email: string; name?: string }[]).filter((a) => a && typeof a.email === 'string')
      : [];
    // Card-open path → trusted, complete attendee list → reconcile removals
    // (drop + cancel guests removed from the event). Plan §8B.
    const draft = await getOrCreateDraft({
      iCalUid,
      providerEventId: body.providerEventId ? String(body.providerEventId) : undefined,
      title: body.title ? String(body.title) : undefined,
      hostEmail: identity.email,
      attendees,
      eventStart: body.start ? String(body.start) : undefined,
      eventEnd: body.end ? String(body.end) : undefined,
      location: body.location ? String(body.location) : undefined,
    }, { reconcileRemovals: true });

    // Gap A — link this event for background lifecycle (move/delete via the watch),
    // but only when X is the event ORGANIZER (don't attach lifecycle to meetings
    // X was merely invited to) and a pass actually exists for it. Keyed on the
    // real iCalUid so the watch's ingest finds it. Reuses the D8 link writer.
    const organizerEmail = body.organizerEmail ? String(body.organizerEmail).toLowerCase() : '';
    const isOrganizer = !!organizerEmail && organizerEmail === identity.email.toLowerCase();
    const sentIds = draft.roster.filter((g) => g.status === 'sent' && g.invitationId).map((g) => g.invitationId as string);
    if (isOrganizer && sentIds.length > 0) {
      await recordInvitationCalendarLink({
        iCalUid,
        providerEventId: body.providerEventId ? String(body.providerEventId) : undefined,
        organizerEmail: identity.email,
        invitationIds: sentIds,
        source: 'addon-link',
        eventStart: draft.eventStart ?? null,
        eventEnd: draft.eventEnd ?? null,
      }).catch((e) => console.warn('[Addon] event link failed:', e));
    }

    // Gap C — tell the card whether background auto-sync (move/delete) is active.
    // Connected → seamless. Not connected → the card offers a one-tap Connect.
    const connected = await isCalendarConnected(identity.email).catch(() => false);
    const calendarSync = {
      connected,
      canConnect: isCalendarOAuthConfigured(),
      // Only meaningful to prompt when X owns the event (lifecycle attaches to it).
      relevant: isOrganizer,
      connectUrl: !connected && isCalendarOAuthConfigured()
        ? connectStartUrl({ email: identity.email })
        : undefined,
    };

    // Host-safe email-template picker list (NOT the admin endpoint — a host has no
    // visitor.templates.view permission). Active email-channel templates only, with
    // the engine default flagged so the card can pre-select it. The card only shows
    // the dropdown when there's a real choice (≥2); one template → no clutter.
    const emailTemplates = await listAddonEmailTemplates();

    json(res, 200, { ...draft, calendarSync, emailTemplates });
    return true;
  }

  // PATCH /addon/draft — persist a host edit (include toggle / name / phone / templates / location).
  if (pathname === '/api/visitor/calendar/addon/draft' && method === 'PATCH') {
    const body = await readBodyJson(req);
    const iCalUid = String(body.iCalUid ?? '').trim();
    if (!iCalUid) { json(res, 422, { error: 'iCalUid required' }); return true; }
    const updated = await patchDraft(iCalUid, body.patch as DraftPatch | undefined);
    if (!updated) { json(res, 404, { error: 'draft not found' }); return true; }
    json(res, 200, updated);
    return true;
  }

  // POST /addon/preview — render the invite email for one guest (no send).
  if (pathname === '/api/visitor/calendar/addon/preview' && method === 'POST') {
    const body = await readBodyJson(req);
    const iCalUid = String(body.iCalUid ?? '').trim();
    const visitorEmail = String(body.visitorEmail ?? '').trim().toLowerCase();
    const draft = iCalUid ? await getDraft(iCalUid) : null;
    const guest = draft?.roster.find((g) => g.email.toLowerCase() === visitorEmail);
    if (!draft || !guest) { json(res, 404, { error: 'guest not found in draft' }); return true; }
    try {
      const hostName = await resolveHostDisplayName(identity.email, identity.name);
      const data: PassEmailData = {
        visitorName: guest.name || visitorEmail,
        hostName,
        purpose: draft.title,
        validFrom: draft.eventStart,
        validUntil: draft.eventEnd,
        passUrl: 'https://preview.example/pass/preview',
        emailTemplateKey: guest.emailTemplateKey,
      };
      const rendered = await renderPassEmailPreview(data);
      // Signed token so the card can open the HTML popup without a Bearer. 30-min TTL:
      // the add-on now mints this at confirm-card BUILD time (not on the Preview click)
      // so the link can open directly and dodge the popup blocker — it must outlive the
      // host reading the confirm card. Expired → preview-html shows a "reopen" message.
      const previewToken = signPreviewToken({
        iCalUid,
        visitorEmail,
        hostName,
        exp: Date.now() + 30 * 60_000,
      });
      json(res, 200, { subject: rendered.subject, html: rendered.html, text: rendered.text, previewToken });
    } catch (err) {
      console.error('[Addon] preview failed:', err);
      json(res, 500, { error: 'Preview failed' });
    }
    return true;
  }

  // POST /addon/send (and /addon/apply alias) — reconcile passes to the toggles:
  // create for newly-included guests, cancel for newly-excluded ones, keep the
  // rest. Used by both "Send passes" (Setup) and "Update passes" (Manage).
  if ((pathname === '/api/visitor/calendar/addon/send' || pathname === '/api/visitor/calendar/addon/apply') && method === 'POST') {
    const body = await readBodyJson(req);
    const iCalUid = String(body.iCalUid ?? '').trim();
    const draft = iCalUid ? await getDraft(iCalUid) : null;
    if (!draft) { json(res, 404, { error: 'draft not found' }); return true; }
    // Self-correct the event window from the times the card re-resolves at send.
    // The draft-open's time fetch (Calendar.Events.get) is flaky on a just-created
    // event, so the stored draft can lack start/end → applyDraft would fail every
    // guest with EVENT_TIME_MISSING. Trust fresh times when the card provides them.
    if (body.start) draft.eventStart = String(body.start);
    if (body.end) draft.eventEnd = String(body.end);
    const result = await applyDraft(draft, { hostName: identity.name });
    // Record the ledger from the active set; draft_authoritative so passive
    // producers reissue/cancel from the curated roster on move/delete.
    await recordDraftMaterialization({
      iCalUid,
      providerEventId: draft.providerEventId,
      organizerEmail: identity.email,
      invitationIds: result.invitationIds,
      eventStart: draft.eventStart ?? null,
      eventEnd: draft.eventEnd ?? null,
    });
    json(res, 200, {
      iCalUid,
      created: result.created,
      cancelled: result.cancelled,
      failed: result.failed,
      activeCount: result.invitationIds.length,
      draft: result.draft,
    });
    return true;
